from google.adk import Session
from typing import Dict, List

class VoiceSessionManager:
    def __init__(self):
        self.sessions: Dict[str, Session] = {}

    def get_or_create_session(self, user_id: str) -> Session:
        if user_id not in self.sessions:
            self.sessions[user_id] = Session(
                user_id=user_id,
                context_window=20,
                max_turns=100,
                state_validators=[
                    self.validate_conversation_coherence,
                    self.validate_no_hallucinations
                ]
            )
        return self.sessions[user_id]

    def validate_conversation_coherence(self, session: Session) -> bool:
        # Check for topic drift, repetition patterns
        recent_turns = session.history[-5:]
        return len(set([t.intent for t in recent_turns])) > 1

    def validate_no_hallucinations(self, session: Session) -> bool:
        # Verify factual consistency
        return True  # Vex will handle this

# Usage
session_mgr = VoiceSessionManager()
session = session_mgr.get_or_create_session("user_123")
response = voice_agent.run(transcript, session=session)

