from vex import VexClient
from google.adk import Agent, MultiAgentSystem

vex_client = VexClient(api_key="your-vex-api-key")

@vex_client.guardrail(
    verifications=["agent_delegation_cycles"],
    max_depth=5
)
def prevent_agent_cycles(ctx):
    """Detect circular delegation patterns"""

    delegation_path = ctx.get_delegation_path()

    # Vex analyzes for cycles
    if ctx.has_cycle(delegation_path):
        return {
            "text": "I'll handle this directly.",
            "bypass_delegation": True
        }

    # Check delegation depth
    if len(delegation_path) > 4:
        return {
            "text": "Escalating to root orchestrator.",
            "redirect_to": "orchestrator"
        }

    return ctx.PROCEED

# Apply to multi-agent system
orchestrator.before_agent_callback = prevent_agent_cycles

from vex import VexClient
import time

vex_client = VexClient(api_key="your-vex-api-key")

@vex_client.guardrail(
    verifications=[
        "safety_filtering",
        "latency_budget:800ms",
        "response_appropriateness"
    ]
)
def voice_pipeline_guard(ctx):
    """Critical path guard for sub-second voice agents"""

    start_time = time.time()

    # Safety filtering FIRST
    safety_score = ctx.safety_check(ctx.message)
    if safety_score < 0.9:
        return {
            "text": "Sorry, I can't help with that.",
            "end_session": True
        }

    # Latency prediction
    predicted_latency = ctx.latency_predict(
        input_length=len(ctx.message),
        agent_count=ctx.active_agents
    )

    if predicted_latency > 750:
        return {
            "text": "Processing...",
            "use_lightweight_model": True
        }

    # Final appropriateness check
    if not ctx.is_appropriate_for_voice(ctx.message):
        return "Could you rephrase that?"

    return ctx.PROCEED

# Install in ADK
voice_agent.before_agent_callback = voice_pipeline_guard
